```javascript
document.addEventListener('DOMContentLoaded', function() {
    const mealOptions = document.querySelectorAll('.grid-item');

    mealOptions.forEach(item => {
        item.addEventListener('click', function() {
            alert(`You clicked on ${item.dataset.meal}`);
        });
    });

    // Example of smooth scrolling for CTA buttons (if needed)
    const ctaBtns = document.querySelectorAll('.cta-btn');

    ctaBtns.forEach(btn => {
        btn.addEventListener('click', function(e) {
            e.preventDefault();
            const targetSection = document.getElementById(this.getAttribute('href').substring(1));
            if(targetSection) {
                targetSection.scrollIntoView({ behavior: 'smooth' });
            }
        });
    });
});
```

