    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body, html {
    font-family: 'Arial', sans-serif;
    background-color: #f4f4f4;
    color: #333;
}

header.navbar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem;
    background-color: #fff;
    border-bottom: 2px solid rgba(0,0,0,.1);
}

.header .logo {
    font-size: 24px;
    color: #333;
    margin-left: 15px;
}

.navbar .login-btn {
    padding: 8px 16px;
    background-color: #ff9f7c;
    border: none;
    cursor: pointer;
    font-size: 14px;
    color: #fff;
    transition: all 0.3s ease;
}

.navbar .login-btn:hover {
    background-color: #e68a62;
}

.hero-section {
    position: relative;
    overflow: hidden;
    padding-top: 50vh; /* 100% of viewport height */
    text-align: center;
}

.hero-image {
    width: 100%;
    height: auto;
    display: block;
    opacity: 0.6; /* Slightly reduce hero image opacity for better text contrast */
}

.tagline {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    font-size: 32px;
    color: #fff;
}

.cta-button {
    display: inline-block;
    margin-top: 24px;
    padding: 10px 20px;
    background-color: #ff9f7c;
    border: none;
    cursor: pointer;
    font-size: 16px;
    color: #fff;
    transition: all 0.3s ease;
}

.cta-button:hover {
    background-color: #e68a62;
}

.meal-options .grid-container {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 1rem;
    margin-top: 3rem;
}

.grid-item {
    background-color: #fff;
    border-radius: 8px;
    overflow: hidden;
    padding: 1rem;
    transition: transform 0.3s ease;
}

.grid-item:hover {
    box-shadow: 0px 5px 20px rgba(0,0,0,.2);
    transform: scale(1.03);
}

.grid-item img {
    width: 100%;
    height: auto;
}

.grid-item h2 {
    font-size: 24px;
    margin-top: 1rem;
}

.grid-item p {
    color: #757575;
    font-size: 16px;
}
