### JavaScript (`scripts.js`)

```javascript
document.addEventListener('DOMContentLoaded', function() {
    const mealOptionsGrid = document.getElementById('meal-options-grid');

    // Sample data for meals, replace with actual API if needed
    const mealData = [
        { id: 1, imgSrc: '/assets/img/meal1.jpeg', description: 'Meal Description 1' },
        { id: 2, imgSrc: '/assets/img/meal2.png', description: 'Meal Description 2' },
        // Add more meals as needed
    ];

    mealData.forEach(meal => {
        const mealDiv = document.createElement('div');
        mealDiv.classList.add('meal-item');

        const mealImg = document.createElement('img');
        mealImg.src = meal.imgSrc;
        mealImg.classList.add('meal-img');

        const mealDescription = document.createElement('p');
        mealDescription.textContent = meal.description;

        const ctaButtonMealItem = document.createElement('button');
        ctaButtonMealItem.textContent = 'View Details';
        ctaButtonMealItem.classList.add('cta-button', 'cta-button-meal-item');

        mealDiv.appendChild(mealImg);
        mealDiv.appendChild(mealDescription);
        mealDiv.appendChild(ctaButtonMealItem);

        mealOptionsGrid.appendChild(mealDiv);
    });
});
```

