### JavaScript (script.js)

```javascript
document.addEventListener("DOMContentLoaded", function() {
    const mealOptionsSection = document.querySelector('.meal-options .grid-container');

    // Meal options data
    const meals = [
        { imgSrc: '/assets/img/meal1.jpeg', title: 'Meal 1', description: 'Description for meal 1' },
        { imgSrc: '/assets/img/meal2.png', title: 'Meal 2', description: 'Description for meal 2' },
        // Add more meals here...
    ];

    // Function to create a grid item
    function createGridItem(meal) {
        const gridItem = document.createElement('div');
        gridItem.classList.add('grid-item');

        const img = document.createElement('img');
        img.src = meal.imgSrc;
        img.alt = meal.title;

        const title = document.createElement('h2');
        title.textContent = meal.title;

        const description = document.createElement('p');
        description.textContent = meal.description;

        const button = document.createElement('button');
        button.classList.add('cta-btn');
        button.textContent = 'View Details';
        button.addEventListener('click', () => alert(`${meal.title} was selected!`));

        gridItem.appendChild(img);
        gridItem.appendChild(title);
        gridItem.appendChild(description);
        gridItem.appendChild(button);

        return gridItem;
    }

    // Populate the meal options section
    meals.forEach(meal => {
        const item = createGridItem(meal);
        mealOptionsSection.appendChild(item);
    });
});
```

