    background-color: transparent;
    border: none;
    outline: none;
}

.hero {
    position: relative;
    width: 100%;
    height: auto;
    padding-top: 5rem;
    display: flex;
    justify-content: center;
    align-items: center;
    text-align: center;
}

.hero .tagline {
    color: white;
    font-size: 2.5em;
    max-width: 80%;
    margin: auto;
}

.cta-button {
    background-color: #ff6347; /* Tomato */
    border: none;
    padding: 1rem 2rem;
    margin-top: 1rem;
    font-size: 1.5em;
    color: white;
    cursor: pointer;
    transition: transform .2s;
}

.cta-button:hover {
    transform: scale(1.05);
}

.meal-options-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 2rem;
    padding: 2rem;
}

.grid-item {
    background-color: #fff;
    border-radius: 8px;
    overflow: hidden;
    box-shadow: 0 4px 6px rgba(0, 0, 0, .1);
    transition: transform .3s;
}

.grid-item:hover {
    transform: scale(1.05);
    box-shadow: 0 6px 8px rgba(0, 0, 0, .2);
}

.modal {
    display: none; /* Hidden by default */
    position: fixed;
    z-index: 9999;
    left: 0;
    top: 0;
    width: 100%;
    height: 100%;
    overflow: auto;
    background-color: rgba(0,0,0,.5);
}

.modal-content {
    position: relative;
    background-color: #fefefe;
    margin: 20% auto;
    padding: 2rem;
    border-radius: 8px;
    width: 80%;
    max-width: 400px;
    box-shadow: 0 6px 12px rgba(0,0,0,.3);
}

.modal-content .close {
